body:
I have noticed that as soon as I declare a clocking in a SystemVerilog interface, both blocking and non-blocking assingments to the signals of all instances of the interface are ignored. This happens even in synthesizable code and when the clocking is completely unused, and stops happening when the clocking is commented out.
I have attached a test case in test_regress format below. The test case defines an Axi5 Lite interface and demonstrates that all assignments to arvalid are ignored. As soon as you comment out the clocking in the interface, the test case works as expected and reaches the `$finish`.
I do not have access to a commercial simulator, but I ran a slight variation of the test case (the same test case plus a clock generator) in Xilinx Vivado, and it reached $finish.

Can you attach an example that shows the issue?  (Must be openly licensed, ideally in test_regress format.)
This is my Verilog test module, `t_interface_clocking_breaks_assignments.v`:
```Verilog
module t (/*AUTOARG*/
   // Inputs
   clk
   );

   input clk;

   logic interface_val_set_flag;
   
   logic aclk;
   logic areset_n;

   assign aclk = clk;
    

    Axi5Lite#(.AXI_ADDR_WIDTH(32), .AXI_DATA_WIDTH(32)) axi5_lite(.aclk(aclk),.aresetn(areset_n));

    always @(posedge(aclk),negedge(areset_n)) begin: test
      if(interface_val_set_flag)
      begin
        if(axi5_lite.arvalid == 1'b1)
        begin
          $display("*-* All Finished *-*");
          $finish();
        end
        else
        begin
          $display("TEST FAIL");
          $stop();
        end
      end
      else
      begin
        interface_val_set_flag <= 1;
        axi5_lite.arvalid <= 1;
      end
    end: test

endmodule

package axi5;

  /// AXI Transaction Response Type.
  typedef enum logic [1:0] {
    OKAY   = 2'b00,
    EXOKAY = 2'b01,
    SLVERR = 2'b10,
    DECERR = 2'b11
  } axi_resp_t;

endpackage

interface Axi5Lite #(
    parameter AXI_DATA_WIDTH = -1,
    parameter AXI_ADDR_WIDTH = -1
) (
    input logic aclk,
    input logic aresetn
);
  // address write (AW) chan
  logic                                         awvalid;
  logic                                         awready;
  logic            [    AXI_ADDR_WIDTH - 1 : 0] awaddr;
  logic            [                       2:0] awprot;

  // write data (wd) chan
  logic                                         wvalid;
  logic                                         wready;
  logic            [    AXI_DATA_WIDTH - 1 : 0] wdata;
  logic            [AXI_DATA_WIDTH / 8 - 1 : 0] wstrb;

  // write response (b) chan
  logic                                         bvalid;
  logic                                         bready;
  axi5::axi_resp_t                              bresp;

  // address read (AR) chan
  logic                                         arvalid;
  logic                                         arready;
  logic            [    AXI_ADDR_WIDTH - 1 : 0] araddr;
  logic            [                       2:0] arprot;

  // read data (d) chan
  logic                                         rvalid;
  logic                                         rready;
  logic            [    AXI_DATA_WIDTH - 1 : 0] rdata;
  axi5::axi_resp_t                              rresp;

  modport FROM(
      input aclk, aresetn, awready, wready, bvalid, bresp, arready, rvalid, rdata, rresp,
      output awvalid, awaddr, awprot, wvalid, wdata, wstrb, bready, arvalid, araddr, arprot, rready
  );
  modport TO(
      output awready, wready, bvalid, bresp, arready, rvalid, rdata, rresp,
      input aclk, aresetn, awvalid, awaddr, awprot, wvalid, wdata, wstrb, bready, arvalid, araddr, arprot, rready
  );

  clocking transmitter_clocking @(posedge (aclk));
    input awready;
    input wready;
    input bvalid;
    input bresp;
    input arready;
    input rvalid;
    input rdata;
    input rresp;
    output awvalid;
    output awaddr;
    output awprot;
    output wvalid;
    output wdata;
    output wstrb;
    output bready;
    output arvalid;
    output araddr;
    output arprot;
    output rready;
  endclocking

endinterface
```
I have copied the t_EXAMPLE.pl perl driver to `t_interface_clocking_breaks_assignments.pl` in order to run the module in the regression test suite. At the time of writing, it looks like this:
```perl
